  |then=.}}{{qif
  |test={{booland
    |1={{{URL|{{{url|}}}}}}
    |2={{{Title|{{{title|}}}}}}}}
  |then=&#32;[{{{URL|{{{url}}}}}} {{{Title|{{{title}}}}}}].
}}{{qif
  |test={{{format|{{{Format|}}}}}}
  |then=&#32;({{{Format|{{{format}}}}}})
}}{{qif
  |test={{{Work|{{{work|}}}}}}
  |then=&#32;''{{{Work|{{{work}}}}}}''.}}{{qif
  |test={{{Publisher|{{{publisher|}}}}}}
  |then=&#32;{{{Publisher|{{{publisher}}}}}}.
}}{{qif
  |test={{{Date|{{{date|}}}}}}  
  |then=&#32;URL accessed on [[{{{Date|{{{date}}}}}}]]{{qif
    |test={{{Year|{{{year|}}}}}}
    |then=, [[{{{Year|{{{year}}}}}}]]
  }}
}}.<noinclude>
{{esoteric}}
[[Category:Citation templates|{{PAGENAME}}]]
</noinclude>
